// jQuery stub - simplified version
// For production, use full jQuery library

if (typeof jQuery === 'undefined') {
    var $ = function(selector) {
        if (typeof selector === 'string') {
            var result = document.querySelectorAll(selector);
            if (result.length === 1) {
                return {
                    0: result[0],
                    length: 1,
                    attr: function(name, value) {
                        if (value === undefined) {
                            return this[0].getAttribute(name);
                        }
                        this[0].setAttribute(name, value);
                        return this;
                    },
                    css: function(name, value) {
                        if (value === undefined) {
                            return this[0].style[name];
                        }
                        this[0].style[name] = value;
                        return this;
                    },
                    click: function(fn) {
                        this[0].onclick = fn;
                        return this;
                    },
                    mousemove: function(fn) {
                        this[0].onmousemove = fn;
                        return this;
                    },
                    unbind: function(event) {
                        if (event === 'click') this[0].onclick = null;
                        if (event === 'mousemove') this[0].onmousemove = null;
                        return this;
                    },
                    addClass: function(className) {
                        this[0].classList.add(className);
                        return this;
                    },
                    removeClass: function(className) {
                        this[0].classList.remove(className);
                        return this;
                    },
                    toggleClass: function(className, condition) {
                        if (condition === undefined) {
                            this[0].classList.toggle(className);
                        } else if (condition) {
                            this[0].classList.add(className);
                        } else {
                            this[0].classList.remove(className);
                        }
                        return this;
                    },
                    show: function() {
                        this[0].style.display = '';
                        return this;
                    },
                    hide: function() {
                        this[0].style.display = 'none';
                        return this;
                    },
                    parent: function() {
                        return $(this[0].parentElement);
                    },
                    offset: function() {
                        var rect = this[0].getBoundingClientRect();
                        return {
                            left: rect.left + window.scrollX,
                            top: rect.top + window.scrollY
                        };
                    },
                    width: function() {
                        return this[0].clientWidth;
                    },
                    height: function() {
                        return this[0].clientHeight;
                    }
                };
            }
        }
        return null;
    };
}
